    "mcq": [
      {
        "id": "q1",
        "questionSubtype": "mcq",
        "question": "Which of the following expressions is a valid polynomial in one variable?",
        "options": [
          "A. $x^2 + \\frac{1}{x}$",
          "B. $3x^{\\sqrt{2}} - 5$",
          "C. $4x^3 - x + 7$",
          "D. $y^{-2} + y$"
        ],
        "answer": "C. $4x^3 - x + 7$",
        "explanation": "Option C contains only non-negative integer exponents (3, 1). Option A has a negative exponent ($x^{-1}$), B has a fractional exponent, and D involves two variables or negative exponents depending on interpretation, but strictly fails the single-variable polynomial definition in this context.",
        "marks": 1,
        "learningOutcomeIds": [
          "LO1"
        ],
        "topicCoverage": [
          "Polynomial Definition",
          "Valid vs Invalid Expressions"
        ],
        "difficulty": "easy",
        "bloomsLevel": "understanding"
      },
      {
        "id": "q2",
        "questionSubtype": "mcq",
        "question": "What is the degree of the polynomial $P(x) = 5x^4 - x + \\sqrt{3}$?",
        "options": [
          "A. 1",
          "B. 2",
          "C. 4",
          "D. 0"
        ],
        "answer": "C. 4",
        "explanation": "The degree is the highest power of the variable $x$. Here, the powers are 4, 1, and 0 (for the constant). The highest is 4.",
        "marks": 1,
        "learningOutcomeIds": [
          "LO2"
        ],
        "topicCoverage": [
          "Degree of a Polynomial"
        ],
        "difficulty": "easy",
        "bloomsLevel": "recall"
      },
      {
        "id": "q3",
